// --- Components ---

function LoadingIndicator() {
  return (
    <div style={{ display: "flex", padding: "8px" }}>
      <div style={{ ...styles.loadingDot, animationDelay: "-0.32s" }} />
      <div style={{ ...styles.loadingDot, animationDelay: "-0.16s" }} />
      <div style={styles.loadingDot} />
      <style>
        {`
          @keyframes bounce {
            0%, 80%, 100% { transform: scale(0); }
            40% { transform: scale(1); }
          }
        `}
      </style>
    </div>
  );
}

function App() {
  const [subject, setSubject] = useState("");
  const [isSetup, setIsSetup] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);

  const chatRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const aiClientRef = useRef<GoogleGenAI | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleInputResize = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInputText(e.target.value);
    e.target.style.height = 'auto';
    e.target.style.height = Math.min(e.target.scrollHeight, 150) + 'px';
  };

  const handleStart = async () => {
    if (!subject.trim()) return;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
      aiClientRef.current = ai;

      chatRef.current = ai.chats.create({
        model: "gemini-3-pro-preview",
        config: {
          systemInstruction: getSystemInstruction(subject),
          temperature: 0.5,
        },
      });

      setIsSetup(true);
      setMessages([
        {
          role: "model",
          text: `Xin chào! Tôi là trợ lý chuyên môn cho môn **${subject}**. Bạn có thắc mắc gì về môn học này cần tôi giải đáp không?`,
        },
      ]);
    } catch (error) {
      console.error("Error initializing chat:", error);
      alert("Có lỗi khi khởi tạo. Vui lòng kiểm tra API Key.");
    }
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || !chatRef.current || isGenerating || isRecording || isTranscribing) return;

    const userMsg = inputText.trim();
    setInputText("");
    setIsGenerating(true);

    const textarea = document.querySelector('textarea');
    if (textarea) textarea.style.height = '24px';

    setMessages((prev) => [...prev, { role: "user", text: userMsg }]);

    try {
      const result = await chatRef.current.sendMessageStream({
        message: userMsg,
      });

      let fullResponseText = "";
      setMessages((prev) => [...prev, { role: "model", text: "" }]);

      for await (const chunk of result) {
        const text = chunk.text;
        if (text) {
          fullResponseText += text;
          setMessages((prev) => {
            const newMessages = [...prev];
            const lastMsg = newMessages[newMessages.length - 1];
            if (lastMsg.role === "model") {
              lastMsg.text = fullResponseText;
            }
            return newMessages;
          });
        }
      }
    } catch (error) {
      console.error("Error sending message:", error);
      setMessages((prev) => [
        ...prev,
        { role: "model", text: "Xin lỗi, đã có lỗi xảy ra khi xử lý yêu cầu của bạn. Vui lòng thử lại." },
      ]);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleReset = () => {
    setIsSetup(false);
    setSubject("");
    setMessages([]);
    chatRef.current = null;
  };

  const handleMicClick = () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = transcribeAudio;
      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Không thể truy cập microphone. Vui lòng kiểm tra quyền truy cập của trình duyệt.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      setIsRecording(false);
    }
  };

  const transcribeAudio = async () => {
    if (audioChunksRef.current.length === 0) return;

    setIsTranscribing(true);
    try {
      const audioBlob = new Blob(audioChunksRef.current, { type: "audio/webm" });
      const base64Audio = await blobToBase64(audioBlob);
      const ai = aiClientRef.current || new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-native-audio-preview-12-2025",
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: "audio/webm",
                data: base64Audio
              }
            },
            {
              text: "Chép lại chính xác lời nói trong đoạn ghi âm này thành văn bản tiếng Việt. Chỉ trả về nội dung văn bản, không thêm bất kỳ lời dẫn nào."
            }
          ]
        }
      });

      const text = response.text;
      if (text) {
        setInputText(prev => (prev ? prev + " " + text : text).trim());
        setTimeout(() => {
          const textarea = document.querySelector('textarea');
          if (textarea) {
            textarea.style.height = 'auto';
            textarea.style.height = Math.min(textarea.scrollHeight, 150) + 'px';
          }
        }, 0);
      }
    } catch (error) {
      console.error("Transcription error:", error);
      alert("Có lỗi khi chuyển đổi giọng nói thành văn bản. Bạn có thể thử lại hoặc nhập trực tiếp.");
    } finally {
      setIsTranscribing(false);
      audioChunksRef.current = [];
    }
  };

  if (!isSetup) {
    return (
      <div style={styles.container}>
        <div style={{ display: 'flex', flex: 1, justifyContent: 'center', alignItems: 'center' }}>
          <div style={styles.setupCard}>
            <div style={{ fontSize: '3.5rem', marginBottom: '1rem' }}>🎓</div>
            <h1 style={styles.setupTitle}>Trợ lý Học tập AI</h1>
            <p style={{ marginBottom: '2rem', color: '#5f6368', lineHeight: '1.6' }}>
              Chào mừng bạn! Vui lòng chọn môn học cần hỗ trợ chuyên môn để bắt đầu.
            </p>

            <select
              style={styles.select}
              value={subject}
              onChange={(e) => setSubject(e.target.value)}
              autoFocus
            >
              <option value="" disabled>-- Chọn môn học --</option>
              {SUBJECT_LIST.map((s) => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>

            <button 
              style={{
                ...styles.button, 
                opacity: subject ? 1 : 0.5,
                transform: subject ? 'scale(1)' : 'scale(0.98)',
                cursor: subject ? 'pointer' : 'not-allowed'
              }} 
              onClick={handleStart}
              disabled={!subject}
            >
              Bắt đầu học ngay
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <style>{`
        @keyframes pulse {
          0% { box-shadow: 0 0 0 0 rgba(217, 48, 37, 0.4); }
          70% { box-shadow: 0 0 0 12px rgba(217, 48, 37, 0); }
          100% { box-shadow: 0 0 0 0 rgba(217, 48, 37, 0); }
        }
      `}</style>

      <div style={styles.header}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <span style={{ fontSize: '1.75rem' }}>📚</span>
          <div>
            <div style={styles.headerTitle}>{subject}</div>
            <div style={{ fontSize: '0.8rem', color: '#5f6368', fontWeight: '500' }}>AI Support Specialist</div>
          </div>
        </div>
        <button style={styles.resetButton} onClick={handleReset}>
          Đổi môn học
        </button>
      </div>

      <div style={styles.chatArea}>
        {messages.map((msg, idx) => (
          <div key={idx} style={styles.messageBubble(msg.role)}>
            {msg.text || (msg.role === "model" && isGenerating && idx === messages.length - 1 ? <LoadingIndicator /> : "")}
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <div style={styles.inputArea}>
        <button
          style={{
            ...styles.iconButton,
            ...(isRecording ? styles.micButtonRecording : {}),
            opacity: isGenerating || isTranscribing ? 0.5 : 1,
            cursor: isGenerating || isTranscribing ? 'not-allowed' : 'pointer',
          }}
          onClick={handleMicClick}
          disabled={isGenerating || isTranscribing}
          title="Nhập bằng giọng nói"
        >
           {isTranscribing ? (
             <div style={styles.loadingDot} />
           ) : (
             <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
               <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path>
               <path d="M19 10v2a7 7 0 0 1-14 0v-2"></path>
               <line x1="12" y1="19" x2="12" y2="23"></line>
               <line x1="8" y1="23" x2="16" y2="23"></line>
             </svg>
           )}
        </button>

        <textarea
          style={styles.messageInput}
          placeholder={isRecording ? "Đang lắng nghe..." : (isTranscribing ? "Đang xử lý giọng nói..." : "Hỏi trợ lý môn học...")}
          value={inputText}
          onChange={handleInputResize}
          onKeyDown={handleKeyDown}
          disabled={isGenerating || isRecording || isTranscribing}
          rows={1}
        />

        <button 
          style={{
            ...styles.iconButton,
            ...styles.sendButton,
            opacity: inputText.trim() && !isGenerating && !isRecording && !isTranscribing ? 1 : 0.4,
            cursor: inputText.trim() && !isGenerating && !isRecording && !isTranscribing ? 'pointer' : 'default',
            transform: inputText.trim() && !isGenerating ? 'scale(1)' : 'scale(0.95)'
          }} 
          onClick={handleSendMessage}
          disabled={!inputText.trim() || isGenerating || isRecording || isTranscribing}
        >
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <line x1="22" y1="2" x2="11" y2="13"></line>
            <polygon points="22 2 15 22 11 13 2 9 22 2"></polygon>
          </svg>
        </button>
      </div>
    </div>
  );
}

