  borderLight: theme === 'light' ? "#f0f2f5" : "#2a2a2a",
  inputBg: theme === 'light' ? "#f0f2f5" : "#2d2d2d",
  bubbleModel: theme === 'light' ? "#ffffff" : "#2d2d2d",
  bubbleModelText: theme === 'light' ? "#1a1a1b" : "#e4e6eb",
  shadow: theme === 'light' ? "rgba(0,0,0,0.05)" : "rgba(0,0,0,0.3)",
  primary: "#0084ff",
